('business:6-3-globalisation:match:36bc542c', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Globalisation”?", "options": ["A tax on a good or service that is imported into a country.", "The process by which business activity around the world has become increasingly interconnected.", "A limit on the amount or value of a good that can be imported.", "The absence of restrictions such as tariffs or quotas on trade between countries."]}'::jsonb, '{"answer": 1, "explain": "“Globalisation” means: The process by which business activity around the world has become increasingly interconnected."}'::jsonb),
('business:6-3-globalisation:match:ce49bb8a', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Tariff”?", "options": ["A limit on the amount or value of a good that can be imported.", "A tax on a good or service that is imported into a country.", "The absence of restrictions such as tariffs or quotas on trade between countries.", "A business that operates (has physical presence) in more than one country."]}'::jsonb, '{"answer": 1, "explain": "“Tariff” means: A tax on a good or service that is imported into a country."}'::jsonb),
('business:6-3-globalisation:match:6170074e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quota”?", "options": ["The absence of restrictions such as tariffs or quotas on trade between countries.", "A business that operates (has physical presence) in more than one country.", "Creating an image or values for a product that are communicated in countries around the world.", "A limit on the amount or value of a good that can be imported."]}'::jsonb, '{"answer": 3, "explain": "“Quota” means: A limit on the amount or value of a good that can be imported."}'::jsonb),
('business:6-3-globalisation:match:e5107c30', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Free Trade”?", "options": ["A business that operates (has physical presence) in more than one country.", "Creating an image or values for a product that are communicated in countries around the world.", "The price of one currency expressed in terms of another currency.", "The absence of restrictions such as tariffs or quotas on trade between countries."]}'::jsonb, '{"answer": 3, "explain": "“Free Trade” means: The absence of restrictions such as tariffs or quotas on trade between countries."}'::jsonb),
('business:6-3-globalisation:match:a2ff60f9', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Multinational Company (MNC)”?", "options": ["A business that operates (has physical presence) in more than one country.", "Creating an image or values for a product that are communicated in countries around the world.", "The price of one currency expressed in terms of another currency.", "A mnemonic: Strong Pound → Imports Cheaper, Exports Dearer."]}'::jsonb, '{"answer": 0, "explain": "“Multinational Company (MNC)” means: A business that operates (has physical presence) in more than one country."}'::jsonb),
('business:6-3-globalisation:match:fff26944', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “International Branding”?", "options": ["The price of one currency expressed in terms of another currency.", "A mnemonic: Strong Pound → Imports Cheaper, Exports Dearer.", "Creating an image or values for a product that are communicated in countries around the world.", "The country in which a multinational company locates its operations."]}'::jsonb, '{"answer": 2, "explain": "“International Branding” means: Creating an image or values for a product that are communicated in countries around the world."}'::jsonb),
