('business:6-3-globalisation:match:1c5cc37f', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “SPICED”?", "options": ["The country in which a multinational company locates its operations.", "A mnemonic: Strong Pound → Imports Cheaper, Exports Dearer.", "A measure of output per worker on average.", "The cost of producing one unit — lower when productivity is higher."]}'::jsonb, '{"answer": 1, "explain": "“SPICED” means: A mnemonic: Strong Pound → Imports Cheaper, Exports Dearer."}'::jsonb),
('business:6-3-globalisation:match:1a1e68d0', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Host Country”?", "options": ["A measure of output per worker on average.", "The cost of producing one unit — lower when productivity is higher.", "When an MNC sends profits earned in a host country back to its home country headquarters.", "The country in which a multinational company locates its operations."]}'::jsonb, '{"answer": 3, "explain": "“Host Country” means: The country in which a multinational company locates its operations."}'::jsonb),
